import * as React from 'react'
import * as TooltipPrimitive from '@radix-ui/react-tooltip'
import { cn } from '../lib/utils'

/* ── Re-exports for compound-component API ── */
const TooltipProvider = TooltipPrimitive.Provider
const Tooltip = TooltipPrimitive.Root
const TooltipTrigger = TooltipPrimitive.Trigger

/* ── Type-variant colour map (M3 tokens) ── */
const typeStyles = {
  default: 'bg-m3-inverse-surface text-m3-inverse-on-surface',
  success: 'bg-m3-primary text-m3-on-primary',
  error: 'bg-m3-error text-m3-on-error',
  warning: 'bg-m3-tertiary text-m3-on-tertiary',
  violet: 'bg-purple-600 text-white',
} as const

type TooltipType = keyof typeof typeStyles

/* ── Alignment map ── */
const alignMap = {
  left: 'start',
  center: 'center',
  right: 'end',
} as const

type BoxAlign = keyof typeof alignMap

/* ── TooltipContent ── */
interface TooltipContentProps
  extends Omit<
    React.ComponentPropsWithoutRef<typeof TooltipPrimitive.Content>,
    'align'
  > {
  /** Colour variant */
  type?: TooltipType
  /** Show the arrow tip */
  tip?: boolean
  /** Horizontal alignment relative to trigger */
  boxAlign?: BoxAlign
  /** Center the text inside the tooltip */
  center?: boolean
}

const TooltipContent = React.forwardRef<
  React.ComponentRef<typeof TooltipPrimitive.Content>,
  TooltipContentProps
>(
  (
    {
      className,
      sideOffset = 6,
      type = 'default',
      tip = true,
      boxAlign = 'center',
      center = true,
      children,
      ...props
    },
    ref,
  ) => (
    <TooltipPrimitive.Content
      ref={ref}
      sideOffset={sideOffset}
      align={alignMap[boxAlign]}
      className={cn(
        'z-50 overflow-hidden rounded-m3-xs px-2.5 py-1.5 text-xs font-medium shadow-md',
        'animate-in fade-in-0 zoom-in-95 data-[state=closed]:animate-out data-[state=closed]:fade-out-0 data-[state=closed]:zoom-out-95',
        typeStyles[type],
        center ? 'text-center' : 'text-start',
        className,
      )}
      {...props}
    >
      {children}
      {tip && (
        <TooltipPrimitive.Arrow
          className={cn(
            'fill-current',
            type === 'default' && 'text-m3-inverse-surface',
            type === 'success' && 'text-m3-primary',
            type === 'error' && 'text-m3-error',
            type === 'warning' && 'text-m3-tertiary',
            type === 'violet' && 'text-purple-600',
          )}
          width={10}
          height={5}
        />
      )}
    </TooltipPrimitive.Content>
  ),
)
TooltipContent.displayName = 'TooltipContent'

/* ── Simple wrapper (single-prop API) ── */
interface SimpleTooltipProps {
  /** Trigger element */
  children: React.ReactNode
  /** Tooltip content */
  text: React.ReactNode
  /** Placement side */
  position?: 'top' | 'bottom' | 'left' | 'right'
  /** Whether to add a 500 ms hover delay */
  delay?: boolean
  /** Horizontal alignment */
  boxAlign?: BoxAlign
  /** Colour variant */
  type?: TooltipType
  /** Show arrow tip */
  tip?: boolean
  /** Center text */
  center?: boolean
}

const SimpleTooltip: React.FC<SimpleTooltipProps> = ({
  children,
  text,
  position = 'top',
  delay = true,
  boxAlign = 'center',
  type = 'default',
  tip = true,
  center = true,
}) => (
  <TooltipPrimitive.Provider delayDuration={delay ? 500 : 0}>
    <TooltipPrimitive.Root>
      <TooltipPrimitive.Trigger asChild>{children}</TooltipPrimitive.Trigger>
      <TooltipContent
        side={position}
        type={type}
        tip={tip}
        boxAlign={boxAlign}
        center={center}
      >
        {text}
      </TooltipContent>
    </TooltipPrimitive.Root>
  </TooltipPrimitive.Provider>
)
SimpleTooltip.displayName = 'SimpleTooltip'

export {
  Tooltip,
  TooltipTrigger,
  TooltipContent,
  TooltipProvider,
  SimpleTooltip,
}
export type { TooltipType, BoxAlign, SimpleTooltipProps, TooltipContentProps }
